# --- Configuration ---
app = Flask(__name__)

UPLOAD_FOLDER = 'data/images'
MODEL_DIR = 'models'
IMAGE_SIZE = (128, 128)
BATCH_SIZE = 32
EPOCHS = 5  # Reduced for quick demonstration. Increase for better accuracy.
VAL_SPLIT = 0.2

# Ensure directories exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

# --- Helper Functions ---

def get_latest_model_path():
    """Returns the path to the latest saved model directory."""
    model_versions = [d for d in os.listdir(MODEL_DIR) if os.path.isdir(os.path.join(MODEL_DIR, d)) and d.startswith('version_')]
    if not model_versions:
        return None
    latest_version = sorted(model_versions, key=lambda x: int(x.split('_')[-1]))[-1]
    return os.path.join(MODEL_DIR, latest_version)

def save_model_with_version(model, labels):
    """Saves the model with a new version number and its corresponding labels."""
    existing_versions = [d for d in os.listdir(MODEL_DIR) if os.path.isdir(os.path.join(MODEL_DIR, d)) and d.startswith('version_')]
    next_version_num = 0
    if existing_versions:
        try:
            version_numbers = [int(v.split('_')[-1]) for v in existing_versions]
            if version_numbers:
                next_version_num = max(version_numbers) + 1
        except ValueError:
            print("Warning: Could not parse model version numbers. Starting new version from 0.")
            next_version_num = len(existing_versions) # Fallback if names are unexpected
    
    version_dir = os.path.join(MODEL_DIR, f'version_{next_version_num}')
    os.makedirs(version_dir, exist_ok=True)
    model.save(version_dir)
    
    with open(os.path.join(version_dir, 'labels.json'), 'w') as f:
        json.dump(labels, f)
        
    print(f"Model and labels saved to {version_dir}")
    return version_dir

def load_latest_model_and_labels():
    """Loads the latest saved model and its associated labels."""
    latest_model_path = get_latest_model_path()
    if not latest_model_path:
        return None, None
    
    try:
        model = tf.keras.models.load_model(latest_model_path)
        with open(os.path.join(latest_model_path, 'labels.json'), 'r') as f:
            labels = json.load(f)
        return model, labels
    except Exception as e:
        print(f"Error loading model or labels from {latest_model_path}: {e}")
        return None, None

def create_training_manifest():
    """Scans UPLOAD_FOLDER and creates a dataframe of image paths and labels."""
    image_paths = []
    labels = []
    
    for label_dir_name in os.listdir(UPLOAD_FOLDER):
        label_path = os.path.join(UPLOAD_FOLDER, label_dir_name)
        if os.path.isdir(label_path):
            for img_file in os.listdir(label_path):
                if img_file.lower().endswith(('.png', '.jpg', '.jpeg', '.gif', '.bmp')):
                    full_img_path = os.path.join(label_path, img_file)
                    image_paths.append(os.path.abspath(full_img_path))
                    labels.append(label_dir_name)
                    
    if not image_paths:
        return pd.DataFrame(), []
        
    df = pd.DataFrame({'image_path': image_paths, 'label': labels})
    unique_labels = sorted(df['label'].unique().tolist()) # Ensure consistent order
    
    return df, unique_labels

# --- API Endpoints ---

@app.route('/')
def index():
    return "Welcome to the Community-Driven AI Training API!"

@app.route('/contribute_example', methods=['POST'])
def contribute_example():
    """
    Allows users to upload a single image with its corresponding label.
    Images are stored in a structured directory (data/images/{label}/).
    """
    if 'image' not in request.files:
        return jsonify({'error': 'No image part in the request'}), 400
    if 'label' not in request.form:
        return jsonify({'error': 'No label provided'}), 400

    image_file = request.files['image']
    label = request.form['label'].lower().strip() # Sanitize label

    if image_file.filename == '':
        return jsonify({'error': 'No selected image file'}), 400

    if image_file and label:
        label_dir = os.path.join(UPLOAD_FOLDER, secure_filename(label))
        os.makedirs(label_dir, exist_ok=True)
        
        # Generate a unique filename using UUID
        filename = secure_filename(str(uuid.uuid4()) + os.path.splitext(image_file.filename)[1])
        filepath = os.path.join(label_dir, filename)
        
        try:
            # Open image with PIL to validate and save correctly
            img = Image.open(image_file.stream)
            img.save(filepath)
            
            return jsonify({
                'message': 'Image contributed successfully',
                'filepath': filepath,
                'label': label
            }), 201
        except Exception as e:
            return jsonify({'error': f'Failed to process image: {e}'}), 500
    
    return jsonify({'error': 'Invalid request'}), 400


@app.route('/upload_csv_manifest', methods=['POST'])
def upload_csv_manifest():
    """
    Allows users to upload a CSV file containing 'image_filename', 'label' pairs.
    This endpoint *does not* handle the actual image files. It's assumed that
    the images referenced in the CSV are either pre-uploaded or will be uploaded
    separately using '/contribute_example' or a similar bulk image upload mechanism.
    This serves primarily as a way to register existing images with labels.
    """
    if 'csv_file' not in request.files:
        return jsonify({'error': 'No CSV file part in the request'}), 400

    csv_file = request.files['csv_file']
    if csv_file.filename == '':
        return jsonify({'error': 'No selected CSV file'}), 400

    if csv_file:
        try:
            df = pd.read_csv(csv_file.stream)
            if 'image_filename' not in df.columns or 'label' not in df.columns:
                return jsonify({'error': 'CSV must contain "image_filename" and "label" columns'}), 400

            # In a full implementation, you would:
            # 1. Validate 'image_filename' paths (e.g., ensure they exist in UPLOAD_FOLDER)
            # 2. Potentially move images if they were uploaded in a bundled ZIP with the CSV.
            # For this example, we just acknowledge the manifest.
            
            return jsonify({
                'message': f'CSV manifest with {len(df)} entries received. Note: This endpoint only processes the manifest. Image files must be present on the server or uploaded separately (e.g., via /contribute_example).',
                'entries_preview': df.head().to_dict('records')
            }), 200
        except Exception as e:
            return jsonify({'error': f'Failed to process CSV file: {e}'}), 500
            
    return jsonify({'error': 'Invalid request'}), 400


@app.route('/train_model', methods=['POST'])
def train_model():
    """
    Triggers the training process using all available contributed data.
    A new model version is saved after training.
    """
    df_manifest, unique_labels = create_training_manifest()
    
    if df_manifest.empty:
        return jsonify({'message': 'No data available for training. Please contribute examples first.'}), 400
        
    num_classes = len(unique_labels)
    if num_classes < 2:
        return jsonify({'message': f'Only {num_classes} classes found. Need at least 2 classes for classification.'}), 400

    # Create a mapping from label string to integer ID
    label_to_id = {label: i for i, label in enumerate(unique_labels)}

    # Create and populate the TensorFlow DenseHashTable once
    keys_tensor = tf.constant(list(label_to_id.keys()), dtype=tf.string)
    values_tensor = tf.constant(list(label_to_id.values()), dtype=tf.int32)
    
    label_map_table = tf.lookup.experimental.DenseHashTable(
        key_dtype=tf.string,
        value_dtype=tf.int32,
        default_value=-1, # Default value for keys not found
        empty_key="EMPTY_KEY", 
        deleted_key="DELETED_KEY" 
    )
    label_map_table.insert(keys_tensor, values_tensor)

    @tf.function
    def _preprocess_image_wrapper(image_path_tensor, label_string_tensor):
        """Loads and preprocesses an image for TensorFlow training."""
        img = tf.io.read_file(image_path_tensor)
        img = tf.image.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.resize(img, IMAGE_SIZE)
        img = tf.cast(img, tf.float32) / 255.0
        
        # Lookup label ID from the hash table
        label_id = label_map_table.lookup(label_string_tensor)
        one_hot_label = tf.one_hot(label_id, depth=num_classes)
        return img, one_hot_label

    # Create tf.data.Dataset
    paths_ds = tf.data.Dataset.from_tensor_slices(df_manifest['image_path'].values)
    labels_ds = tf.data.Dataset.from_tensor_slices(df_manifest['label'].values)
    
    dataset = tf.data.Dataset.zip((paths_ds, labels_ds))
    dataset = dataset.map(_preprocess_image_wrapper, num_parallel_calls=tf.data.AUTOTUNE)
    dataset = dataset.shuffle(buffer_size=1000).batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)

    # Split dataset for training and validation
    # Note: tf.data.experimental.cardinality().numpy() returns UNKNOWN_CARDINALITY (-2)
    # for datasets where the size cannot be determined statically (e.g., from generators).
    # For a dataset derived from a manifest, it should be known.
    dataset_size_elements = len(df_manifest) # Number of actual elements
    
    # Calculate batch-level sizes
    total_batches = (dataset_size_elements + BATCH_SIZE - 1) // BATCH_SIZE
    train_batches = int((1 - VAL_SPLIT) * total_batches)
    val_batches = total_batches - train_batches

    if train_batches == 0:
        return jsonify({'message': f'Not enough data to create training batches. Minimum {BATCH_SIZE} examples required per class for a split.'}), 400
    if val_batches == 0 and total_batches > 0:
         print("Warning: Only one batch available. No separate validation set will be used.")
         train_ds = dataset
         val_ds = None
    elif total_batches > 0:
        train_ds = dataset.take(train_batches)
        val_ds = dataset.skip(train_batches)
    else: # total_batches == 0
        return jsonify({'message': 'No batches could be created from the available data.'}), 400

    # Build or load model
    model, _ = load_latest_model_and_labels()
    if model is None or model.output_shape[-1] != num_classes:
        print("No compatible model found or number of classes changed. Building a new model.")
        model = models.Sequential([
            layers.Conv2D(32, (3, 3), activation='relu', input_shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(64, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(128, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Flatten(),
            layers.Dense(128, activation='relu'),
            layers.Dense(num_classes, activation='softmax')
        ])
        model.compile(optimizer='adam',
                      loss='categorical_crossentropy',
                      metrics=['accuracy'])
    else:
        print(f"Loaded existing model for transfer learning/fine-tuning. Current model has {model.output_shape[-1]} classes.")
        # Re-compile to ensure optimizer state is reset for new training run
        model.compile(optimizer='adam',
                      loss='categorical_crossentropy',
                      metrics=['accuracy'])
    
    model.summary()
    
    # Train the model
    history = model.fit(
        train_ds,
        epochs=EPOCHS,
        validation_data=val_ds if val_ds else None
    )
    
    # Save the new model version
    saved_model_path = save_model_with_version(model, unique_labels)
    
    results = {
        'message': 'Model training completed',
        'training_epochs': EPOCHS,
        'final_accuracy': float(history.history['accuracy'][-1]),
        'num_classes': num_classes,
        'class_labels': unique_labels,
        'model_path': saved_model_path
    }
    if 'val_accuracy' in history.history:
        results['final_val_accuracy'] = float(history.history['val_accuracy'][-1])

    return jsonify(results), 200

@app.route('/predict', methods=['POST'])
def predict():
    """
    Takes an image upload and returns a prediction using the latest trained model.
    """
    if 'image' not in request.files:
        return jsonify({'error': 'No image part in the request'}), 400

    image_file = request.files['image']
    if image_file.filename == '':
        return jsonify({'error': 'No selected image file'}), 400

    model, labels = load_latest_model_and_labels()
    if model is None or labels is None:
        return jsonify({'error': 'No trained model available. Please train a model first using /train_model.'}), 503

    try:
        img_bytes = image_file.read()
        img = tf.io.decode_image(img_bytes, channels=3, expand_animations=False)
        img = tf.image.resize(img, IMAGE_SIZE)
        img = tf.cast(img, tf.float32) / 255.0
        img = tf.expand_dims(img, 0) # Add batch dimension

        predictions = model.predict(img)
        predicted_class_id = np.argmax(predictions[0])
        predicted_class_label = labels[predicted_class_id]
        confidence = float(predictions[0][predicted_class_id])

        return jsonify({
            'prediction': predicted_class_label,
            'confidence': confidence,
            'all_probabilities': {labels[i]: float(p) for i, p in enumerate(predictions[0])}
        }), 200

    except Exception as e:
        return jsonify({'error': f'Failed to make prediction: {e}'}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)